// // This module decrements its value on each rising edge of the clock signal and resets to all ones when the reset input is asserted.
module top_module(
    input clk, reset,
    output reg [3:0] led
);always @(posedge clk) begin
        if(reset) begin
            led <= 4'b0000;
        end else begin
            led <= led + 1;
        end
    end

endmodule
